VALUES
  ('retired-d0d1b9a2-moex-00430', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司生產某項產品的實際工資率為$100，本年度實際人工小時數為 8,000 小時，產生效率 差異$98,000（有利），工資率差異為$16,000（不利），則標準人工小時數為何？', '["8,000小時", "9,000小時", "10,000小時", "11,000小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00431', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '已知某公司之銷貨額為$800,000，利潤為$200,000，變動成本為銷貨收入之65%，則營運槓桿 為何？', '["0.38", "0.71", "1.40", "2.60"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00432', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司計算產品成本時，若該公司的製造成本都是變動成本，而銷管費用都是固定成本，則 下列敘述何者正確？', '["銷貨毛利將大於邊際貢獻", "銷貨毛利將等於邊際貢獻", "銷貨毛利將小於邊際貢獻", "變動成本法之淨利將大於全部成本法之淨利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00433', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '企業編製預算資料包括：① 生產預算，②銷貨預算，③直接原料耗用預算，④直接原料採購 預算，⑤預計損益表。下列編製步驟何者正確？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00434', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司產銷某產品，目前產能供不應求，產銷量為 24,000 單位，營收$456,000，銷貨成本 $348,000，其中20%為固定製造費用。今有乙公司向甲公司提出9,600單位、單價$16之特殊 訂單。甲公司考慮應否接受此特殊訂單，下列何者正確？', '["應接受，因為會使淨利增加14,400", "不應接受，因為會使淨利減少14,400", "應接受，因為會使淨利增加28,800", "不應接受，因為會使淨利減少28,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00435', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司考慮處分X事業部，此事業部的存貨帳面價值屬於下列何者？', '["付現成本", "機會成本", "沈沒成本", "差異成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00436', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司擬進行一項投資計畫，第一年初投資成本為$600,000，未來四年每年底可產生淨現金 流入$200,000，若公司要求之報酬率為10%，則此投資之內部報酬率為何？（4期，利率10%， 普通年金現值因子=3.16987；4期，利率12%，普通年金現值因子=3.03735）', '["小於10%", "介於10%~12%之間", "12%", "大於12%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00437', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司計畫以$3,000,000投資一部機器，估計耐用年限10年，無殘值，採直線法折舊。公司 預計此項投資計畫可使未來10年每年增加稅後淨利$500,000，則此機器原始投資的會計報酬 率為何？', '["6.67%", "16.67%", "26.67%", "33.33% 13640"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00438', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司正計畫投資一部新機器，成本$1,000,000，耐用年限4年，無殘值，採年數合計法提列 折舊。預計未來4年每年可減少稅前營運成本$300,000，此係按第1年初投資當時之物價水 準估計，營運成本於每年年底支付。公司未調整通貨膨脹之最低要求報酬率為10%，所得稅 稅率為20%，每年通貨膨脹率10%，則在考慮通貨膨脹及所得稅下，該投資計畫之淨現值為 何？（四捨五入取整數）（利率21%，1期複利現值因子=0.8264；2期複利現值因子=0.6830； 3期複利現值因子=0.5645；4期複利現值因子=0.4665）', '["$(123,265)", "$(100,240)", "$48,395", "$64,668"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00439', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', 'A公司於X5年起，採取成本領導之經營策略，該公司經評估認為此策略可於X6年呈現施行 成效。試問如該公司此項策略執行成功，則營業利益分析的結果會是如何？', '["營業利益的增加係來自價格回收因素與成長因素，而非生產力因素", "營業利益的增加係來自生產力因素與成長因素，而非價格回收因素", "營業利益的增加係來自產業市場規模因素與價格回收因素，而非成長因素", "營業利益的增加係來自產業市場規模因素與成長因素，而非價格回收因素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "8ee6291c8bf6", "answer_pdf_sha1": "acc4e9be62e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
